const item = $input.first().json;
const fileData = item.fileData;
const source_hash = item.source_hash;
const source_file_name = item.source_file_name;

// Decode base64 CSV
const csvText = Buffer.from(fileData, 'base64').toString('utf-8');

// Parse CSV lines (ignore comments and empty lines)
const lines = csvText.split('\n').map(l => l.trim()).filter(l => l && !l.startsWith('#'));
const headers = lines[0].split(',').map(h => h.trim());
const rows = [];

for (let i = 1; i < lines.length; i++) {
  const values = lines[i].split(',').map(v => v.trim());
  if (values.length < 2) continue;

  const row = {};
  headers.forEach((h, idx) => { row[h] = values[idx] || ''; });

  // Map to unified schema
  const amount_excl = parseFloat(row['amount_excl']) || null;
  const vat_rate = parseFloat(row['vat_rate']) || null;
  const vat_given = row['vat'] !== undefined && row['vat'] !== '' ? parseFloat(row['vat']) : null;
  const amount_incl_given = row['amount_incl'] !== undefined && row['amount_incl'] !== '' ? parseFloat(row['amount_incl']) : null;

  // Calculate VAT
  let vat = vat_given;
  if (vat === null && vat_rate !== null && amount_excl !== null) {
    vat = Math.round(amount_excl * vat_rate / 100 * 100) / 100;
  } else if (vat === null && amount_excl !== null) {
    vat = Math.round(amount_excl * 0.15 * 100) / 100;
  }

  // Calculate amount_incl_vat
  let amount_incl_vat = amount_incl_given;
  if (amount_incl_vat === null && amount_excl !== null && vat !== null) {
    amount_incl_vat = Math.round((amount_excl + vat) * 100) / 100;
  }

  rows.push({
    json: {
      invoice_number: row['invoice_number'] || '',
      supplier_number: row['supplier_number'] || '',
      supplier_name: row['supplier_name'] || '',
      department: row['department'] || '',
      invoice_date: row['invoice_date'] || '',
      amount_excl_vat: amount_excl,
      vat: vat,
      amount_incl_vat: amount_incl_vat,
      vat_rate_used: vat_rate || 15,
      source_hash,
      source_file_name
    }
  });
}

return rows;

const crypto = require('crypto');

const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0];

if (!binaryKey) {
  throw new Error('No file received in webhook');
}

const binaryData = item.binary[binaryKey];
const buffer = Buffer.from(binaryData.data, 'base64');
const hash = crypto.createHash('sha256').update(buffer).digest('hex');
const fileName = binaryData.fileName || 'unknown.csv';

return [{
  json: {
    source_hash: hash,
    source_file_name: fileName,
    fileData: binaryData.data
  }
}];

const items = $input.all();
const results = [];

// Get today's date in Africa/Johannesburg timezone
const nowJHB = new Date(new Date().toLocaleString('en-US', { timeZone: 'Africa/Johannesburg' }));
nowJHB.setHours(0, 0, 0, 0);

for (const item of items) {
  const r = item.json;
  const notes = [];

  // 1. Required fields check
  if (!r.invoice_number) notes.push('Missing invoice_number');
  if (!r.supplier_number) notes.push('Missing supplier_number');
  if (!r.supplier_name) notes.push('Missing supplier_name');
  if (!r.department) notes.push('Missing department');
  if (r.amount_excl_vat === null) notes.push('Missing amount_excl_vat');
  if (r.vat === null) notes.push('Missing vat');
  if (r.amount_incl_vat === null) notes.push('Missing amount_incl_vat');
  if (!r.invoice_date) notes.push('Missing invoice_date');

  // 2. Date not in the future
  if (r.invoice_date) {
    const invoiceDate = new Date(r.invoice_date);
    if (invoiceDate > nowJHB) {
      notes.push('invoice_date is in the future');
    }
  }

  // 3. Math check: amount_incl_vat = amount_excl_vat + vat (±0.01 tolerance)
  if (r.amount_excl_vat !== null && r.vat !== null && r.amount_incl_vat !== null) {
    const expected = Math.round((r.amount_excl_vat + r.vat) * 100) / 100;
    if (Math.abs(expected - r.amount_incl_vat) > 0.01) {
      notes.push(`Math error: ${r.amount_excl_vat} + ${r.vat} should equal ${expected}, got ${r.amount_incl_vat}`);
    }
  }

  // 4. VAT rate check (default 15%)
  if (r.amount_excl_vat !== null && r.vat !== null) {
    const expectedVat = Math.round(r.amount_excl_vat * 0.15 * 100) / 100;
    if (r.vat_rate_used !== 15 && Math.abs(expectedVat - r.vat) > 0.01) {
      notes.push(`VAT mismatch: expected ${expectedVat} at 15%, got ${r.vat}`);
    }
  }

  const valid = notes.length === 0;

  results.push({
    json: {
      ...r,
      valid,
      validation_notes: valid ? null : notes.join('; ')
    }
  });
}

return results;
